import{_ as e,c as a,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Stage 1: Bootstrap - Structure Product Idea | Agent App Factory Tutorial","description":"Learn how the Bootstrap stage transforms vague product ideas into a clear, structured input/idea.md document. This tutorial covers Bootstrap Agent responsibilities, the superpowers:brainstorm skill, the standard idea.md structure, and quality checklist.","frontmatter":{"title":"Stage 1: Bootstrap - Structure Product Idea | Agent App Factory Tutorial","sidebarTitle":"Structure Product Idea","subtitle":"Stage 1: Bootstrap - Structure Product Idea","description":"Learn how the Bootstrap stage transforms vague product ideas into a clear, structured input/idea.md document. This tutorial covers Bootstrap Agent responsibilities, the superpowers:brainstorm skill, the standard idea.md structure, and quality checklist.","tags":["pipeline","Bootstrap","product idea"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),o={name:"hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function n(r,t,l,p,d,c){return s(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="stage-1-bootstrap-structure-product-idea" tabindex="-1">Stage 1: Bootstrap - Structure Product Idea <a class="header-anchor" href="#stage-1-bootstrap-structure-product-idea" aria-label="Permalink to &quot;Stage 1: Bootstrap - Structure Product Idea&quot;">​</a></h1><p>Bootstrap is the first stage of the Agent App Factory pipeline, responsible for organizing your vague product idea into a clear <code>input/idea.md</code> document. This is the starting point for all subsequent stages (PRD, UI, Tech, etc.), determining the direction and quality of the entire project.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will be able to:</p><ul><li>Organize vague product ideas into a standard <code>input/idea.md</code> document</li><li>Understand Bootstrap Agent&#39;s responsibility boundaries (collect information only, don&#39;t create requirements)</li><li>Know how to use the superpowers:brainstorm skill to deeply explore product ideas</li><li>Determine what information should be included in the Bootstrap stage and what should not</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>You might have a product idea, but describe it vaguely:</p><ul><li>&quot;I want to build a fitness app&quot; (too general)</li><li>&quot;Build an app like Xiaohongshu&quot; (no differentiation)</li><li>&quot;Users need a better task management tool&quot; (no specific problem)</li></ul><p>Such vague descriptions will cause subsequent stages (PRD, UI, Tech) to lack clear input, and the generated application may completely deviate from your expectations.</p><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p>When you&#39;re ready to start the pipeline and meet the following conditions:</p><ol><li><strong>Have a preliminary product idea</strong> (even if it&#39;s just one sentence)</li><li><strong>Haven&#39;t started writing requirement documents</strong> (PRD is in later stages)</li><li><strong>Haven&#39;t decided on tech stack or UI style</strong> (these are in later stages)</li><li><strong>Want to control product scope and avoid over-design</strong> (Bootstrap stage will clarify non-goals)</li></ol><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>Before starting the Bootstrap stage, ensure:</p><ul><li>✅ <a href="./../../start/init-project/">Project initialization</a> completed</li><li>✅ <a href="./../../start/pipeline-overview/">7-stage pipeline overview</a> understood</li><li>✅ AI assistant installed and configured (Claude Code recommended)</li><li>✅ Your product idea ready (even if vague)</li></ul></div><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><h3 id="what-is-the-bootstrap-stage" tabindex="-1">What is the Bootstrap Stage? <a class="header-anchor" href="#what-is-the-bootstrap-stage" aria-label="Permalink to &quot;What is the Bootstrap Stage?&quot;">​</a></h3><p><strong>Bootstrap</strong> is the starting point of the entire pipeline. Its sole responsibility is to <strong>organize fragmented product ideas into a structured document</strong>.</p><div class="info custom-block"><p class="custom-block-title">Not a Product Manager</p><p>Bootstrap Agent is not a product manager. It will not create requirements or design features for you. Its tasks are:</p><ul><li>Collect information you&#39;ve already provided</li><li>Organize and structure this information</li><li>Present it according to standard templates</li></ul><p>It won&#39;t decide &quot;what features should exist,&quot; it will only help you clearly express &quot;what you want.&quot;</p></div><h3 id="why-structure" tabindex="-1">Why Structure? <a class="header-anchor" href="#why-structure" aria-label="Permalink to &quot;Why Structure?&quot;">​</a></h3><p>Imagine telling a chef: &quot;I want to eat something good&quot;</p><ul><li>❌ Vague description: Chef can only guess and might make something you don&#39;t want to eat at all</li><li>✅ Structured description: &quot;I want a spicy Sichuan dish without cilantro that goes well with rice&quot;</li></ul><p>The Bootstrap stage transforms &quot;I want to eat something good&quot; into &quot;spicy Sichuan dish without cilantro.&quot;</p><h3 id="output-document-structure" tabindex="-1">Output Document Structure <a class="header-anchor" href="#output-document-structure" aria-label="Permalink to &quot;Output Document Structure&quot;">​</a></h3><p>The Bootstrap stage generates <code>input/idea.md</code>, including the following sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>Content</th><th>Example</th></tr></thead><tbody><tr><td><strong>Brief Description</strong></td><td>1-2 sentences summarizing the product</td><td>&quot;A mobile expense tracking app helping young people quickly record daily spending&quot;</td></tr><tr><td><strong>Problem</strong></td><td>Core pain points users face</td><td>&quot;Young people discover overspending at month-end but don&#39;t know where the money went&quot;</td></tr><tr><td><strong>Target User</strong></td><td>Specific user persona</td><td>&quot;18-30-year-old young people who just started working, with average technical skills&quot;</td></tr><tr><td><strong>Core Value</strong></td><td>Why it&#39;s valuable</td><td>&quot;Record expenses in 3 seconds, saving 80% time compared to manual tracking&quot;</td></tr><tr><td><strong>Assumptions</strong></td><td>2-4 testable assumptions</td><td>&quot;Users are willing to spend 2 minutes learning the app if it helps control budget&quot;</td></tr><tr><td><strong>Non-Goals</strong></td><td>Clearly define what not to do</td><td>&quot;No budget planning or financial advice&quot;</td></tr></tbody></table><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-prepare-your-product-idea" tabindex="-1">Step 1: Prepare Your Product Idea <a class="header-anchor" href="#step-1-prepare-your-product-idea" aria-label="Permalink to &quot;Step 1: Prepare Your Product Idea&quot;">​</a></h3><p>Before starting the pipeline, clarify your product idea. It can be a complete description or just a simple thought.</p><p><strong>Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to build a fitness app that helps fitness beginners track their training, including exercise type, duration, calories, and weekly statistics.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Ideas Can Be Rough</p><p>Even if it&#39;s just one sentence, that&#39;s fine. Bootstrap Agent will use the superpowers:brainstorm skill to help you fill in complete information.</p></div><h3 id="step-2-start-pipeline-to-bootstrap-stage" tabindex="-1">Step 2: Start Pipeline to Bootstrap Stage <a class="header-anchor" href="#step-2-start-pipeline-to-bootstrap-stage" aria-label="Permalink to &quot;Step 2: Start Pipeline to Bootstrap Stage&quot;">​</a></h3><p>Execute in the Factory project directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start pipeline (if not started yet)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or directly specify starting from bootstrap</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>The CLI will display current status and available stages.</p><h3 id="step-3-ai-assistant-reads-bootstrap-agent-definition" tabindex="-1">Step 3: AI Assistant Reads Bootstrap Agent Definition <a class="header-anchor" href="#step-3-ai-assistant-reads-bootstrap-agent-definition" aria-label="Permalink to &quot;Step 3: AI Assistant Reads Bootstrap Agent Definition&quot;">​</a></h3><p>The AI assistant (e.g., Claude Code) will automatically read <code>agents/bootstrap.agent.md</code> to understand its responsibilities and constraints.</p><div class="info custom-block"><p class="custom-block-title">Agent Responsibilities</p><p>Bootstrap Agent can only:</p><ul><li>Read product ideas provided by users in conversation</li><li>Write to <code>input/idea.md</code></li></ul><p>It cannot:</p><ul><li>Read other files</li><li>Write to other directories</li><li>Create new requirements</li></ul></div><h3 id="step-4-mandatory-use-of-superpowers-brainstorm-skill" tabindex="-1">Step 4: Mandatory Use of superpowers:brainstorm Skill <a class="header-anchor" href="#step-4-mandatory-use-of-superpowers-brainstorm-skill" aria-label="Permalink to &quot;Step 4: Mandatory Use of superpowers:brainstorm Skill&quot;">​</a></h3><p>This is the key step of the Bootstrap stage. The AI assistant <strong>must</strong> first invoke the <code>superpowers:brainstorm</code> skill, even if you think the information is already complete.</p><p><strong>Role of brainstorm skill</strong>:</p><ol><li><strong>Deeply explore the essence of the problem</strong>: Discover blind spots in your description through structured questioning</li><li><strong>Clarify target user persona</strong>: Help you think clearly about &quot;who exactly are we selling to&quot;</li><li><strong>Verify core value</strong>: Find differentiation through competitor comparison</li><li><strong>Identify implicit assumptions</strong>: List those assumptions you take for granted but haven&#39;t verified</li><li><strong>Control product scope</strong>: Clarify boundaries through non-goals</li></ol><p><strong>What the AI assistant will do</strong>:</p><ul><li>Invoke <code>superpowers:brainstorm</code> skill</li><li>Provide your original idea</li><li>Ask you questions through skill-generated questions</li><li>Collect your answers and refine the idea</li></ul><div class="danger custom-block"><p class="custom-block-title">Skipping This Step Will Be Rejected</p><p>The Sisyphus scheduler will verify if the brainstorm skill was used. If not, Bootstrap Agent&#39;s output will be rejected and must be re-executed.</p></div><h3 id="step-5-confirm-idea-md-content" tabindex="-1">Step 5: Confirm idea.md Content <a class="header-anchor" href="#step-5-confirm-idea-md-content" aria-label="Permalink to &quot;Step 5: Confirm idea.md Content&quot;">​</a></h3><p>After Bootstrap Agent completes, it will generate <code>input/idea.md</code>. You need to carefully check:</p><p><strong>Checkpoints ✅</strong>:</p><ol><li><p><strong>Is brief description clear?</strong></p><ul><li>✅ Includes: what to build + for whom + what problem to solve</li><li>❌ Too generic: &quot;A tool to improve efficiency&quot;</li></ul></li><li><p><strong>Is problem description specific?</strong></p><ul><li>✅ Includes: scenario + difficulty + negative result</li><li>❌ Too vague: &quot;User experience is poor&quot;</li></ul></li><li><p><strong>Is target user clear?</strong></p><ul><li>✅ Has specific persona (age/occupation/technical skills)</li><li>❌ Vague: &quot;Everyone&quot;</li></ul></li><li><p><strong>Is core value quantifiable?</strong></p><ul><li>✅ Has specific benefit (saves 80% time)</li><li>❌ Vague: &quot;Improve efficiency&quot;</li></ul></li><li><p><strong>Are assumptions testable?</strong></p><ul><li>✅ Can be verified through user research</li><li>❌ Subjective judgment: &quot;Users will like it&quot;</li></ul></li><li><p><strong>Are non-goals sufficient?</strong></p><ul><li>✅ Lists at least 3 features not to do</li><li>❌ Missing or too few</li></ul></li></ol><h3 id="step-6-choose-continue-retry-or-pause" tabindex="-1">Step 6: Choose Continue, Retry, or Pause <a class="header-anchor" href="#step-6-choose-continue-retry-or-pause" aria-label="Permalink to &quot;Step 6: Choose Continue, Retry, or Pause&quot;">​</a></h3><p>After confirmation, the CLI will display options:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Select</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> an</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> action:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] Continue (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">enter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PRD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] Retry (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">regenerate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> idea.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] Pause (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">continue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> later</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Suggest Checking in Code Editor First</p><p>Before confirming in AI assistant, open <code>input/idea.md</code> in code editor and check word by word. Once entering PRD stage, modification cost will be higher.</p></div><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="pitfall-1-idea-description-too-vague" tabindex="-1">Pitfall 1: Idea Description Too Vague <a class="header-anchor" href="#pitfall-1-idea-description-too-vague" aria-label="Permalink to &quot;Pitfall 1: Idea Description Too Vague&quot;">​</a></h3><p><strong>Wrong example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to build a fitness app</span></span></code></pre></div><p><strong>Consequence</strong>: Bootstrap Agent will ask many questions through brainstorm skill to supplement information.</p><p><strong>Suggestion</strong>: Describe clearly from the start:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to build a mobile fitness app that helps fitness beginners track their training, including exercise type, duration, calories, and weekly statistics.</span></span></code></pre></div><h3 id="pitfall-2-including-technical-implementation-details" tabindex="-1">Pitfall 2: Including Technical Implementation Details <a class="header-anchor" href="#pitfall-2-including-technical-implementation-details" aria-label="Permalink to &quot;Pitfall 2: Including Technical Implementation Details&quot;">​</a></h3><p><strong>Wrong example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I hope to build with React Native, backend with Express, database with Prisma...</span></span></code></pre></div><p><strong>Consequence</strong>: Bootstrap Agent will reject this content (it only collects product ideas, tech stack is decided in Tech stage).</p><p><strong>Suggestion</strong>: Only say &quot;what to do,&quot; not &quot;how to do it.&quot;</p><h3 id="pitfall-3-target-user-description-too-general" tabindex="-1">Pitfall 3: Target User Description Too General <a class="header-anchor" href="#pitfall-3-target-user-description-too-general" aria-label="Permalink to &quot;Pitfall 3: Target User Description Too General&quot;">​</a></h3><p><strong>Wrong example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Everyone who needs fitness</span></span></code></pre></div><p><strong>Consequence</strong>: Subsequent stages cannot clarify design direction.</p><p><strong>Suggestion</strong>: Clarify persona:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18-30-year-old fitness beginners just starting systematic training, with average technical skills, hoping for simple recording and statistics viewing.</span></span></code></pre></div><h3 id="pitfall-4-non-goals-missing-or-too-few" tabindex="-1">Pitfall 4: Non-Goals Missing or Too Few <a class="header-anchor" href="#pitfall-4-non-goals-missing-or-too-few" aria-label="Permalink to &quot;Pitfall 4: Non-Goals Missing or Too Few&quot;">​</a></h3><p><strong>Wrong example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Non-goals: None</span></span></code></pre></div><p><strong>Consequence</strong>: Subsequent PRD and Code stages may over-design, increasing technical complexity.</p><p><strong>Suggestion</strong>: List at least 3 items:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Non-goals:</span></span>
<span class="line"><span>- Team collaboration and social features (MVP focuses on individual)</span></span>
<span class="line"><span>- Complex data analysis and reporting</span></span>
<span class="line"><span>- Integration with third-party fitness devices</span></span></code></pre></div><h3 id="pitfall-5-assumptions-not-testable" tabindex="-1">Pitfall 5: Assumptions Not Testable <a class="header-anchor" href="#pitfall-5-assumptions-not-testable" aria-label="Permalink to &quot;Pitfall 5: Assumptions Not Testable&quot;">​</a></h3><p><strong>Wrong example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Assumption: Users will like our design</span></span></code></pre></div><p><strong>Consequence</strong>: Cannot be verified through user research, MVP may fail.</p><p><strong>Suggestion</strong>: Write testable assumptions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Assumption: Users are willing to spend 5 minutes learning the app if it helps systematically track training.</span></span></code></pre></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>The core of Bootstrap stage is <strong>structuring</strong>:</p><ol><li><strong>Input</strong>: Your vague product idea</li><li><strong>Process</strong>: AI assistant deeply explores through superpowers:brainstorm skill</li><li><strong>Output</strong>: <code>input/idea.md</code> matching standard template</li><li><strong>Validation</strong>: Check if description is specific, user is clear, value is quantifiable</li></ol><div class="tip custom-block"><p class="custom-block-title">Key Principles</p><ul><li>❌ What not to do: Don&#39;t create requirements, don&#39;t design features, don&#39;t decide tech stack</li><li>✅ What to do only: Collect information, organize and structure, present according to template</li></ul></div><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../stage-prd/">Stage 2: PRD - Generate Product Requirements Document</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to transform idea.md into MVP-level PRD</li><li>What PRD includes (user stories, feature list, non-functional requirements)</li><li>How to clarify MVP scope and priorities</li><li>Why PRD cannot include technical details</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>Bootstrap Agent definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>Pipeline definition (Bootstrap stage)</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>Orchestrator definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>Key constraints</strong>:</p><ul><li><strong>Mandatory use of brainstorm skill</strong>: bootstrap.agent.md:70-71</li><li><strong>Prohibit technical details</strong>: bootstrap.agent.md:47</li><li><strong>Prohibit merging multiple ideas</strong>: bootstrap.agent.md:48</li><li><strong>Output file must be saved to input/idea.md</strong>: bootstrap.agent.md:50</li></ul><p><strong>Exit conditions</strong> (pipeline.yaml:15-18):</p><ul><li>idea.md exists</li><li>idea.md describes a coherent product idea</li><li>Agent has used <code>superpowers:brainstorm</code> skill for deep exploration</li></ul><p><strong>Skill content framework</strong>:</p><ul><li><strong>Thinking framework</strong>: Extract vs create, problem-first, concreteness, assumption validation</li><li><strong>Question templates</strong>: About problem, target user, core value, MVP assumptions, non-goals</li><li><strong>Information extraction techniques</strong>: Reverse-engineer problem from features, extract requirements from complaints, identify implicit assumptions</li><li><strong>Quality checklist</strong>: Completeness, specificity, consistency, prohibitions</li><li><strong>Decision principles</strong>: Ask questions first, problem-oriented, concrete over abstract, testability, scope control</li><li><strong>Common scenario handling</strong>: User provides one sentence only, describes many features, describes competitors, idea contradictions</li><li><strong>Example comparisons</strong>: Bad idea.md vs good idea.md</li></ul></details>`,92)])])}const g=e(o,[["render",n]]);export{h as __pageData,g as default};
